import React, { useState } from "react";
import { motion } from "framer-motion";
import { Star, Sparkles, ArrowRight, Zap, Gift, Camera } from "lucide-react";
import { useNavigate } from "react-router-dom";
import useWindowSize from "../hooks/useWindowSize";

const CARDS = [
  {
    id: "creators",
    label: "Creators",
    emoji: "≡ƒÄ¼",
    Icon: Camera,
    headline: "Go viral together",
    sub: "Showcase our quirky props to your audience. Earn rewards, get free kits, and create reels that blow up.",
    perks: ["Free Prop Kits", "Revenue Share", "Co-branded Reels", "Priority Support"],
    gradient: "linear-gradient(135deg, #F58529 0%, #DD2A7B 100%)",
    light: "#fff0f8",
    accent: "#DD2A7B",
    angle: "-2deg",
  },
  {
    id: "planners",
    label: "Event Planners",
    emoji: "≡ƒÄ¬",
    Icon: Sparkles,
    headline: "Build epic events",
    sub: "Get exclusive trade discounts, custom themed props, and a dedicated partner manager for every event.",
    perks: ["40% Trade Discount", "Custom Props", "Dedicated Manager", "Rush Delivery"],
    gradient: "linear-gradient(135deg, #DD2A7B 0%, #8134AF 100%)",
    light: "#f5eeff",
    accent: "#8134AF",
    angle: "1.5deg",
  },
  {
    id: "brands",
    label: "Brands",
    emoji: "ΓÜí",
    Icon: Zap,
    headline: "Amplify your brand",
    sub: "Co-branded products, branded event experiences, and unique campaigns that cut through the noise.",
    perks: ["Co-branded Merch", "Brand Campaigns", "Bulk Pricing", "White-label Options"],
    gradient: "linear-gradient(135deg, #8134AF 0%, #515BD4 100%)",
    light: "#eef0ff",
    accent: "#515BD4",
    angle: "-1deg",
  },
];

const Collaboration = () => {
  const [hovered, setHovered] = useState(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const navigate = useNavigate();
  const { isMobile } = useWindowSize();

  const handleNext = () => setCurrentIndex((prev) => (prev + 1) % CARDS.length);
  const handlePrev = () => setCurrentIndex((prev) => (prev - 1 + CARDS.length) % CARDS.length);

  return (
    <section
      style={{
        position: "relative",
        padding: isMobile ? "3rem 0.85rem 2.5rem" : "6rem 1rem 5rem",
        background: "linear-gradient(180deg, #fff 0%, #fdf5ff 40%, #fff8f0 100%)",
        overflow: "hidden",
      }}
    >
      {/* Background radial glows */}
      <div style={{ position: "absolute", inset: 0, pointerEvents: "none", overflow: "hidden" }}>
        <div style={{ position: "absolute", top: "-10%", left: "-10%", width: "45%", height: "55%", borderRadius: "50%", background: "radial-gradient(circle, rgba(245,133,41,0.08) 0%, transparent 70%)" }} />
        <div style={{ position: "absolute", bottom: "-10%", right: "-10%", width: "45%", height: "55%", borderRadius: "50%", background: "radial-gradient(circle, rgba(129,52,175,0.08) 0%, transparent 70%)" }} />
      </div>

      {/* Floating emoji decorations */}
      {["≡ƒÄë", "Γ£¿", "≡ƒÄê", "≡ƒÄè", "≡ƒÆ¥"].map((e, i) => (
        <motion.div key={i}
          animate={{ y: [0, -20 + i * 4, 0], rotate: [0, 12 * (i % 2 === 0 ? 1 : -1), 0] }}
          transition={{ duration: 4 + i * 1.2, repeat: Infinity, ease: "easeInOut", delay: i * 0.7 }}
          style={{
            position: "absolute", fontSize: i === 0 ? "2.5rem" : "1.8rem",
            opacity: 0.18, pointerEvents: "none",
            top: ["10%", "70%", "20%", "80%", "40%"][i],
            left: ["5%", "88%", "92%", "5%", "95%"][i],
          }}
        >{e}</motion.div>
      ))}

      <div style={{ maxWidth: "1100px", margin: "0 auto", position: "relative", zIndex: 1 }}>

        {/* ΓöÇΓöÇ Header ΓöÇΓöÇ */}
        <div style={{ textAlign: "center", marginBottom: isMobile ? "2rem" : "4rem" }}>
          <motion.div
            initial={{ opacity: 0, scale: 0.8 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
            style={{
              display: "inline-flex", alignItems: "center", gap: "0.5rem",
              padding: "0.4rem 1.2rem", borderRadius: "999px",
              background: "linear-gradient(135deg, #F58529, #DD2A7B)",
              color: "#fff", fontSize: "0.7rem", fontWeight: 900,
              letterSpacing: "0.16em", textTransform: "uppercase",
              marginBottom: "1rem", boxShadow: "0 4px 20px rgba(245,133,41,0.30)",
            }}
          >
            <Gift size={13} />
            Join the Party
          </motion.div>

          <motion.h2
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ delay: 0.1 }}
            style={{
              fontSize: isMobile ? "1.55rem" : "clamp(2.2rem, 5.5vw, 3.8rem)", fontWeight: 900, lineHeight: 1.05,
              background: "linear-gradient(90deg,#F58529,#DD2A7B,#8134AF)",
              WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text",
              marginBottom: "0.8rem",
            }}
          >
            Let's create magic together.
          </motion.h2>
          <p style={{ color: "#7a5a3a", fontWeight: 600, fontSize: isMobile ? "0.85rem" : "1.05rem", opacity: 0.7, maxWidth: "480px", margin: "0 auto", lineHeight: 1.6 }}>
            Creator, planner, or brand ΓÇö pick your collaboration style and let's make something extraordinary.
          </p>
        </div>

        {/* ΓöÇΓöÇ Cards Section ΓöÇΓöÇ */}
        <div style={{ position: "relative" }}>
          <div style={{
            display: isMobile ? "flex" : "grid",
            gridTemplateColumns: isMobile ? "none" : "repeat(auto-fit, minmax(280px, 1fr))",
            gap: isMobile ? "0" : "1.75rem",
            transform: isMobile ? `translateX(-${currentIndex * (100 / CARDS.length)}%)` : "none",
            transition: isMobile ? "transform 0.5s cubic-bezier(0.4, 0, 0.2, 1)" : "none",
            width: isMobile ? `${CARDS.length * 100}%` : "100%",
            alignItems: "start",
          }}>
            {CARDS.map((card, i) => {
              const isHovered = hovered === card.id;
              return (
                <div
                  key={card.id}
                  style={{
                    width: isMobile ? `${100 / CARDS.length}%` : "auto",
                    padding: isMobile ? "0 0.5rem" : "0",
                    boxSizing: "border-box"
                  }}
                >
                  <motion.div
                    initial={{ opacity: 0, y: 40 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: i * 0.12, type: "spring", stiffness: 120, damping: 18 }}
                    onMouseEnter={() => setHovered(card.id)}
                    onMouseLeave={() => setHovered(null)}
                    style={{ rotate: isHovered ? "0deg" : (isMobile ? "0deg" : card.angle) }}
                  >
                    {/* Ticket / pass card */}
                    <motion.div
                      animate={{ y: isHovered ? -10 : 0, scale: isHovered ? 1.03 : 1 }}
                      transition={{ type: "spring", stiffness: 260, damping: 22 }}
                      style={{
                        borderRadius: "2rem",
                        overflow: "hidden",
                        boxShadow: isHovered
                          ? `0 32px 64px -12px ${card.accent}44, 0 2px 0 ${card.accent}33`
                          : "0 12px 40px -8px rgba(0,0,0,0.14)",
                        background: "#fff",
                        border: `2px solid ${card.accent}22`,
                        cursor: "pointer",
                      }}
                    >
                      {/* Gradient header strip */}
                      <div style={{
                        background: card.gradient,
                        padding: isMobile ? "1.2rem 1.25rem 1rem" : "2rem 1.75rem 1.5rem",
                        position: "relative", overflow: "hidden",
                      }}>
                        {/* Big blurred emoji bg */}
                        <div style={{
                          position: "absolute", top: "-10px", right: "-10px",
                          fontSize: isMobile ? "4rem" : "6rem", opacity: 0.18, lineHeight: 1,
                          userSelect: "none", pointerEvents: "none",
                        }}>{card.emoji}</div>

                        {/* Top row: icon pill + label */}
                        <div style={{ display: "flex", alignItems: "center", gap: "0.6rem", marginBottom: isMobile ? "0.7rem" : "1.2rem" }}>
                          <div style={{
                            background: "rgba(255,255,255,0.22)", backdropFilter: "blur(8px)",
                            borderRadius: "999px", padding: "0.35rem 1rem",
                            color: "#fff", fontSize: "0.65rem", fontWeight: 900,
                            letterSpacing: "0.14em", textTransform: "uppercase",
                            display: "flex", alignItems: "center", gap: "0.4rem",
                          }}>
                            <card.Icon size={13} />
                            {card.label}
                          </div>
                        </div>

                        <h3 style={{
                          color: "#fff", fontWeight: 900,
                          fontSize: isMobile ? "1.2rem" : "clamp(1.4rem, 2.5vw, 1.9rem)",
                          lineHeight: 1.1, marginBottom: "0.4rem",
                        }}>{card.headline}</h3>
                        <p style={{ color: "rgba(255,255,255,0.85)", fontSize: isMobile ? "0.78rem" : "0.85rem", fontWeight: 600, lineHeight: 1.5 }}>
                          {card.sub}
                        </p>
                      </div>

                      {/* Scallop divider between header and body */}
                      <div style={{
                        display: "flex", alignItems: "center",
                        padding: "0 1.5rem",
                        margin: "-1px 0",
                        background: "#fff",
                      }}>
                        {Array.from({ length: 10 }).map((_, j) => (
                          <div key={j} style={{
                            flex: 1, height: "22px",
                            borderRadius: "0 0 50% 50%",
                            background: card.gradient,
                          }} />
                        ))}
                      </div>

                      {/* Body */}
                      <div style={{ background: "#fff", padding: isMobile ? "1rem 1.25rem 1.4rem" : "1.5rem 1.75rem 2rem" }}>
                        {/* Perks list */}
                        <p style={{
                          fontSize: "0.6rem", fontWeight: 900,
                          letterSpacing: "0.18em", textTransform: "uppercase",
                          color: card.accent, marginBottom: "0.75rem",
                        }}>What you get</p>
                        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "0.5rem", marginBottom: "1.5rem" }}>
                          {card.perks.map((perk, j) => (
                            <div key={j} style={{
                              display: "flex", alignItems: "center", gap: "0.4rem",
                              background: card.light,
                              borderRadius: "0.75rem",
                              padding: isMobile ? "0.35rem 0.55rem" : "0.45rem 0.7rem",
                              fontSize: isMobile ? "0.68rem" : "0.75rem", fontWeight: 800, color: "#3d2a1a",
                            }}>
                              <Star size={10} style={{ fill: card.accent, color: card.accent, flexShrink: 0 }} />
                              {perk}
                            </div>
                          ))}
                        </div>

                        {/* CTA button */}
                        <motion.button
                          onClick={() => navigate("/contact")}
                          whileTap={{ scale: 0.96 }}
                          style={{
                            width: "100%",
                            padding: isMobile ? "0.7rem 1.2rem" : "0.9rem 1.5rem",
                            borderRadius: "999px",
                            border: "none",
                            background: card.gradient,
                            color: "#fff",
                            fontWeight: 900,
                            fontSize: isMobile ? "0.72rem" : "0.8rem",
                            letterSpacing: "0.08em",
                            textTransform: "uppercase",
                            cursor: "pointer",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                            gap: "0.5rem",
                            boxShadow: `0 6px 24px ${card.accent}44`,
                            transition: "box-shadow 0.2s",
                          }}
                        >
                          Partner with us <ArrowRight size={15} />
                        </motion.button>
                      </div>
                    </motion.div>
                  </motion.div>
                </div>
              );
            })}
          </div>

          {/* Mobile Dot Indicators */}
          {isMobile && (
            <div style={{
              display: "flex",
              justifyContent: "center",
              gap: "0.6rem",
              marginTop: "1.5rem",
            }}>
              {CARDS.map((_, i) => (
                <button
                  key={i}
                  onClick={() => setCurrentIndex(i)}
                  style={{
                    width: i === currentIndex ? "1.5rem" : "0.5rem",
                    height: "0.5rem",
                    borderRadius: "999px",
                    border: "none",
                    background: i === currentIndex
                      ? "linear-gradient(90deg, #F58529, #DD2A7B)"
                      : "rgba(0,0,0,0.1)",
                    transition: "all 0.3s ease",
                    cursor: "pointer",
                    padding: 0,
                  }}
                />
              ))}
            </div>
          )}
        </div>

        {/* ΓöÇΓöÇ Bottom tagline ΓöÇΓöÇ */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ delay: 0.4 }}
          style={{ textAlign: "center", marginTop: isMobile ? "1.75rem" : "3.5rem" }}
        >
          <p style={{
            fontSize: isMobile ? "0.82rem" : "1rem", fontWeight: 700,
            color: "#7a5a3a", opacity: 0.7, lineHeight: 1.6,
          }}>
            Already a partner? DM us on{" "}
            <a
              href="https://instagram.com/surprisesutra"
              target="_blank"
              rel="noopener noreferrer"
              style={{
                fontWeight: 900,
                background: "linear-gradient(90deg,#F58529,#DD2A7B)",
                WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text",
                textDecoration: "none",
              }}
            >
              @surprisesutra
            </a>{" "}
            or drop us a mail ≡ƒÄë
          </p>
        </motion.div>
      </div>
    </section>
  );
};

export default Collaboration;

import React, { useEffect, useState } from 'react';
import { motion, useSpring, AnimatePresence } from 'framer-motion';
import { Sparkles, Star } from 'lucide-react';

const CustomCursor = () => {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [isHovering, setIsHovering] = useState(false);
  const [isClicking, setIsClicking] = useState(false);
  const [sparkles, setSparkles] = useState([]);
  const [trail, setTrail] = useState([]);
  const [isTouchDevice, setIsTouchDevice] = useState(false);

  const springConfig = { damping: 25, stiffness: 200, mass: 0.5 };
  const cursorX = useSpring(0, springConfig);
  const cursorY = useSpring(0, springConfig);

  useEffect(() => {
    const updatePosition = (e) => {
      let targetX = e.touches && e.touches.length > 0 ? e.touches[0].clientX : e.clientX;
      let targetY = e.touches && e.touches.length > 0 ? e.touches[0].clientY : e.clientY;

      if (targetX === undefined || targetY === undefined) return;

      const interactive = e.target.closest('button, a');
      if (interactive) {
        const rect = interactive.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;

        targetX += (centerX - targetX) * 0.15;
        targetY += (centerY - targetY) * 0.15;
        setIsHovering(true);
      } else {
        setIsHovering(false);
      }

      cursorX.set(targetX - 16);
      cursorY.set(targetY - 16);
      setMousePosition({ x: targetX, y: targetY });

      // Add to trail
      if (Math.abs(targetX - mousePosition.x) > 5 || Math.abs(targetY - mousePosition.y) > 5) {
        const newTrailIdx = Date.now();
        setTrail(prev => [{ id: newTrailIdx, x: targetX, y: targetY }, ...prev].slice(0, 8));
      }
    };

    const handleDown = (e) => {
      setIsClicking(true);
      let targetX = e.touches && e.touches.length > 0 ? e.touches[0].clientX : e.clientX;
      let targetY = e.touches && e.touches.length > 0 ? e.touches[0].clientY : e.clientY;

      if (targetX === undefined || targetY === undefined) return;

      const colors = ['#FF6B6B', '#4ECDC4', '#FFE66D', '#FF9F43'];
      const newSparkles = Array.from({ length: 12 }).map((_, i) => ({
        id: Date.now() + i,
        x: targetX,
        y: targetY,
        angle: (i * 30) * (Math.PI / 180),
        color: colors[i % colors.length],
        scale: Math.random() * 1.5 + 0.5
      }));
      setSparkles(prev => [...prev.slice(-24), ...newSparkles]);
    };

    const handleUp = () => setIsClicking(false);

    window.addEventListener('mousemove', updatePosition);
    window.addEventListener('touchmove', updatePosition, { passive: true });
    window.addEventListener('mousedown', handleDown);
    window.addEventListener('touchstart', handleDown, { passive: true });
    window.addEventListener('mouseup', handleUp);
    window.addEventListener('touchend', handleUp);

    return () => {
      window.removeEventListener('mousemove', updatePosition);
      window.removeEventListener('touchmove', updatePosition);
      window.removeEventListener('mousedown', handleDown);
      window.removeEventListener('touchstart', handleDown);
      window.removeEventListener('mouseup', handleUp);
      window.removeEventListener('touchend', handleUp);
    };
  }, [cursorX, cursorY, mousePosition]);

  useEffect(() => {
    const timer = setInterval(() => {
      if (trail.length > 0) setTrail(prev => prev.slice(0, -1));
      if (sparkles.length > 0) setSparkles(prev => prev.slice(4));
    }, 100);
    return () => clearInterval(timer);
  }, [trail, sparkles]);

  return (
    <div className="fixed inset-0 pointer-events-none z-[9999] overflow-hidden">
      {trail.map((point, i) => (
        <motion.div
            key={point.id}
            initial={{ opacity: 0.4, scale: 1 }}
            animate={{ opacity: 0, scale: 0 }}
            className="absolute rounded-full bg-brand-primary"
            style={{
                left: point.x - 2,
                top: point.y - 2,
                width: 4,
                height: 4,
                filter: 'blur(1px)',
                opacity: (8 - i) / 20
            }}
        />
      ))}

      <AnimatePresence>
        {sparkles.map((s) => (
          <motion.div
            key={s.id}
            initial={{ opacity: 1, scale: 0, x: s.x, y: s.y }}
            animate={{ 
              opacity: 0, 
              scale: s.scale, 
              x: s.x + Math.cos(s.angle) * 100, 
              y: s.y + Math.sin(s.angle) * 100,
              rotate: 360
            }}
            exit={{ opacity: 0 }}
            className="absolute"
            style={{ color: s.color }}
          >
            <Star fill="currentColor" size={12} />
          </motion.div>
        ))}
      </AnimatePresence>

      <motion.div
        className="fixed top-0 left-0 w-8 h-8 rounded-full border-2 border-brand-primary/20 flex items-center justify-center"
        style={{
          x: cursorX,
          y: cursorY,
          scale: isClicking ? 0.8 : (isHovering ? 2.2 : 1),
          borderColor: isHovering ? 'rgba(255, 107, 107, 1)' : 'rgba(255, 107, 107, 0.2)',
          backgroundColor: isHovering ? 'rgba(255, 107, 107, 0.05)' : 'transparent'
        }}
      >
        <AnimatePresence>
          {isHovering && (
            <motion.div
              initial={{ opacity: 0, rotate: -180 }}
              animate={{ opacity: 1, rotate: 0 }}
              exit={{ opacity: 0, rotate: 180 }}
            >
              <Sparkles className="text-brand-primary animate-pulse" size={12} />
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>

      <motion.div
        className="fixed top-0 left-0 w-2 h-2 rounded-full bg-brand-primary shadow-[0_0_10px_rgba(255,107,107,0.5)]"
        animate={{
          x: mousePosition.x - 4,
          y: mousePosition.y - 4,
          scale: isClicking ? 2 : 1,
        }}
      />
    </div>
  );
};

export default CustomCursor;

import { useState, useEffect } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { Menu, X, ShoppingCart, User } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import Logo from "../assets/new_logo.png";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  const getCart = () => {
    const raw = localStorage.getItem("surprise_sutra_cart");
    return raw ? JSON.parse(raw) : [];
  };

  const [cartItems, setCartItems] = useState(getCart());
  const totalItems = cartItems.reduce((sum, i) => sum + i.qty, 0);

  useEffect(() => {
    const handler = () => setCartItems(getCart());
    window.addEventListener("storage", handler);
    window.addEventListener("cartUpdated", handler);
    return () => {
      window.removeEventListener("storage", handler);
      window.removeEventListener("cartUpdated", handler);
    };
  }, []);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const navLinks = [
    { name: "Home", path: "/" },
    { name: "DIY Kits", path: "/diy-kits" },
    { name: "Supplies", path: "/products" },
    { name: "Party Talk", path: "/contact" },
  ];

  return (
    <nav className={`fixed top-0 left-0 right-0 z-[100] transition-all duration-500 font-brand ${
      scrolled ? "py-2 px-4 md:py-4 md:px-6" : "py-4 px-6 md:py-8 md:px-10"
    }`}>
      <div className={`max-w-7xl mx-auto transition-all duration-500 ${
        scrolled ? "bg-white/90 backdrop-blur-xl shadow-[0_20px_50px_rgba(221,42,123,0.1)] rounded-[3rem] px-4 py-2 md:px-8 md:py-4 border-4 border-brand-primary/20" : "px-0"
      }`}>
        <div className="flex justify-between items-center">
          {/* Logo */}
          <Link to="/" className="group">
             <motion.div 
               whileHover={{ scale: 1.05 }}
               className="h-[60px] md:h-[104px] flex items-center"
             >
                <img src={Logo} alt="Surprise Sutra Logo" className="h-full w-auto object-contain" />
             </motion.div>
          </Link>

          {/* Desktop Nav */}
          <div className="hidden lg:flex items-center gap-10">
            {navLinks.map((link) => (
              <Link 
                key={link.path} 
                to={link.path}
                className={`text-sm font-heading font-black uppercase tracking-wider transition-all relative group ${
                  location.pathname === link.path ? "text-brand-primary" : "text-brand-brown/40 hover:text-brand-brown"
                }`}
              >
                {link.name}
                <motion.span 
                  className={`absolute -bottom-2 left-0 w-full h-1 bg-brand-primary blob-mask transition-all ${
                    location.pathname === link.path ? "opacity-100 scale-100" : "opacity-0 scale-0 group-hover:opacity-100 group-hover:scale-100"
                  }`} 
                />
              </Link>
            ))}
          </div>

          {/* Actions */}
          <div className="flex items-center gap-2 md:gap-3">
            {/* Cart */}
            <button 
              onClick={() => navigate('/cart')}
              className="w-10 h-10 md:w-14 md:h-14 blob-mask-alt bg-brand-pink/10 flex items-center justify-center text-brand-primary relative hover:bg-brand-primary hover:text-white transition-all group border-none"
            >
              <ShoppingCart size={20} className="md:size-[24px] group-hover:scale-110 transition-transform" />
              {totalItems > 0 && (
                <span className="absolute -top-1 -right-1 w-5 h-5 md:w-6 md:h-6 bg-brand-brown text-white text-[8px] md:text-[10px] font-black flex items-center justify-center blob-mask border-2 border-white animate-pulse">
                  {totalItems}
                </span>
